                Dict{String,Any}(
                    "DefinitionS3Location" => DefinitionS3Location,
                    "RoleArn" => RoleArn,
                    "WorkflowArn" => WorkflowArn,
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
